#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use HTML::Escape;

my $comment = param('comment') || '';
$comment = html_escape($comment);

print "Content-type: text/html\n\n";
print "<div>$comment</div>";

